// Brings every package published from this directory up to what it must be before
// its tarball is built: the main one and each per-platform binary package.
//
// Three jobs, and each exists because something generated by `napi create-npm-dirs`
// is not right on its own:
//
//   1. Copy the license, the notice and the third-party notices in. Apache-2.0
//      section 4 requires a redistribution to carry the first two, each of these
//      packages is a separate redistribution, and an npm consumer never sees the
//      repository root. The third exists because the binary is not only ton-net:
//      the `.node` links its whole dependency tree in, so shipping it redistributes
//      eighty-odd other projects whose licenses ask for their notices too, and a
//      reader on npm has no `Cargo.toml` to find them in.
//   2. Add the ones npm would drop to the files allowlist. npm ships a LICENSE
//      whether or not an allowlist mentions it; nothing else gets that treatment.
//   3. Rewrite the per-platform readme. The generated one points at the package
//      name prefix, which here is `@nirapod-labs/ton-net` and is not a package anyone can
//      install. The package to install is `ton-net`.
//
// All three are applied rather than edited in, so regenerating the directories
// does not quietly undo them. npm runs this from `prepack`.

import {
  copyFileSync,
  existsSync,
  mkdirSync,
  readFileSync,
  readdirSync,
  statSync,
  writeFileSync,
} from "node:fs";
import { dirname, join } from "node:path";
import { fileURLToPath } from "node:url";

const here = dirname(fileURLToPath(import.meta.url));
const binding = join(here, "..");
const root = join(binding, "..", "..");

const LICENSE_FILES = ["LICENSE", "NOTICE", "THIRD-PARTY-LICENSES.md"];
for (const name of LICENSE_FILES) {
  if (!existsSync(join(root, name))) {
    throw new Error(`${name} is missing from the repository root; nothing to stage`);
  }
}

const main = JSON.parse(readFileSync(join(binding, "package.json"), "utf8"));
const installed = main.name;

/** The readme a per-platform package publishes, given the platform it holds. */
function platformReadme(name, platform) {
  return `# \`${name}\`

The prebuilt **${platform}** binary for [\`${installed}\`](https://www.npmjs.com/package/${installed}).

There is no reason to install this package directly. \`${installed}\` lists it as an
optional dependency, and npm installs whichever one matches the current platform
and skips the rest, so installing \`${installed}\` is the whole story.

Source and issues: <${main.repository.url.replace(/^git\+/, "").replace(/\.git$/, "")}>
`;
}

const targets = [binding];
const platforms = join(binding, "npm");
if (existsSync(platforms)) {
  for (const entry of readdirSync(platforms)) {
    const dir = join(platforms, entry);
    if (statSync(dir).isDirectory()) {
      targets.push(dir);
    }
  }
}

for (const target of targets) {
  mkdirSync(target, { recursive: true });
  for (const name of LICENSE_FILES) {
    copyFileSync(join(root, name), join(target, name));
  }

  const manifestPath = join(target, "package.json");
  const manifest = JSON.parse(readFileSync(manifestPath, "utf8"));
  if (Array.isArray(manifest.files)) {
    const missing = LICENSE_FILES.filter(
      (name) => name !== "LICENSE" && !manifest.files.includes(name),
    );
    if (missing.length > 0) {
      manifest.files.push(...missing);
      writeFileSync(manifestPath, `${JSON.stringify(manifest, null, 2)}\n`);
    }
  }

  // The main package keeps the readme that is written by hand; only the generated
  // per-platform ones are replaced. The platform is the tail of the package name,
  // which is also what the loader matches on at runtime, so it is the name a reader
  // debugging an install will recognize.
  if (target !== binding) {
    const platform = manifest.name.slice(`${main.napi.packageName}-`.length);
    writeFileSync(join(target, "README.md"), platformReadme(manifest.name, platform));
  }
}

// Progress goes to stderr. npm runs this from `prepack`, so anything written to
// stdout lands in front of the JSON that `npm pack --json` is expected to emit and
// makes it unparseable for whatever reads it.
console.error(`prepared ${targets.length} package(s)`);
